var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"얍.","JPN":"やあっ。","ENG":"Yap.","TWN":"嘿。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"나이스 타이밍?","JPN":"ナイスタイミング？","ENG":"Nice timing?","TWN":"來得正好？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네. 완전 나이스 타이밍이에요.","JPN":"はい、ドンピシャです。","ENG":"Yes. Nice timing indeed.","TWN":"是的，絕對來得正好。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"잘못된 거 아닌가 싶었는데 이렇게 도와주러 오시고. 웬일로 이름값 좀 하셨네요?","JPN":"やられたと思っていましたが、こちらを手伝いに来てくれるなんて。今日だけは株が急上昇ですね。","ENG":"I thought maybe something happened to you, but you made it and even helped me out. Maybe sometimes Credere does mean trust.","TWN":"還以為來不了了呢。真是難得，克蕾妲莉終於做出人如其名的事。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레를 모욕하지 마라, 어이-.","JPN":"クレデレをなめるんじゃないぞ、コラ。","ENG":"Do not speak ill of Credere. Arr.","TWN":"不許你這樣說克蕾妲莉。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"웬일이 아니라 매일 이런다, 어이-.","JPN":"今日だけじゃなくて常にだ、コラ。","ENG":"It is not \\"sometimes.\\" Credere is always the icon of trust. Arr.","TWN":"不是難得，克蕾妲莉一直這樣。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"네네. 장해요 우리 크레데레.","JPN":"はいはい、よくできました。クレデレちゃん。","ENG":"Yeah, yeah. I'm so proud of you, Credere.","TWN":"好好好，我們克蕾妲莉最棒。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"언니가 진~하게 한 번 안아드릴게요.","JPN":"お姉ちゃんが抱きしめてあげましょうか？","ENG":"Let me give you a biiiiig hug.","TWN":"姊姊我會好～～好抱你一次的。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"힉.","JPN":"ひいっ。","ENG":"*Gasp*","TWN":"唔。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"시그마시그마. 유피가 미쳤습니다.","JPN":"シグマシグマ、ユピがご乱心です。","ENG":"Sigma-Sigma. Yuppie's gone crazy.","TWN":"西格瑪西格瑪。悠菲瘋了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"싸우다가 머리를 세게 얻어맞은 건가요?","JPN":"戦闘で頭を強く打ったんでしょうか？","ENG":"Did someone hit her head while fighting?","TWN":"打架的時候腦子被狠狠地打壞了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"후후.","JPN":"ふふ。","ENG":"Ha hah.","TWN":"呵呵。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"…미스터 쮸빕. 아무래도 크레데레가 너무 늦은 것 같습니다.","JPN":"……ミスター・チュピー。どうやらクレデレの到着が遅すぎたようです。","ENG":"...Mr. Squirty, it seems like Credere was too late.","TWN":"……咻咻先生。看來克蕾妲莉來得太晚了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이렇게 된 이상 어쩔 수 없죠.","JPN":"こうなったら、もう仕方ないですね。","ENG":"It seems that there is no other choice.","TWN":"既然這樣，那也沒辦法了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"장례지도사 자격증을 보유한 크레데레가 두 분을 천국으로 모시겠습니다.","JPN":"葬儀屋の資格を持つクレデレが、お二方をあの世まで送ってあげましょう。","ENG":"As a certified undertaker, Credere shall lead you both to the afterlife.","TWN":"持有禮儀師資格證的克蕾妲莉將送你們二位上路。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"크레데레는 장수할 테니 천년 정도 뒤에 다시 만나죠.","JPN":"クレデレは長生きすると思うので、次会うのはきっと千年後ですね。","ENG":"You will see Credere in about a thousand years, as Credere will live long and prosper.","TWN":"克蕾妲莉會長壽的，一千年之後再見吧。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"그럼 아디오스-.","JPN":"では、アディオス。","ENG":"Adios.","TWN":"那就拜拜啦——"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"뭐라는 거야. 시그마가 든 이거 안 보여요?","JPN":"何言ってるんですか。シグマが何を持っているか、見えませんか？","ENG":"Whatever. Credere, did you see what Sigma is holding?","TWN":"你說什麼呢。沒看到西格瑪拿著這個嗎？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"보세요. 저 아줌마를 상대로 제대로 지켜냈다고요.","JPN":"見てくださいよ。あのおばさん相手に、これをちゃんと守り抜いたんですよ。","ENG":"Look. She kept that safe against the Vice President.","TWN":"看吧，我們成功從大嬸手裡保住這個箱子了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIBBON_DEBT_NECK_NULL","text":{"KOREA":"이건?","JPN":"これは？","ENG":"Does that mean–","TWN":"這是……？"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응, 맞아!","JPN":"うん、そうだよ！","ENG":"Yes!","TWN":"是，沒錯！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"보물찾기는 끝이다, 얼!","JPN":"お宝探しはこれで終了だ、ARRR！","ENG":"The treasure hunt is over, yarr!","TWN":"尋寶結束了，唷呵！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"마귀상어를 물리친 시그마 해적단의 승리야!!","JPN":"ババアサメを倒したシグマ海賊団の勝利だよ！！","ENG":"The Sigma Pirates defeated the wicked shark and are victorious!","TWN":"擊敗魔鬼鯊的西格瑪海盜團勝利啦！！"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAKER_DEBT_NECK_NULL","text":{"KOREA":"드디어… 드디어 이 지긋지긋한 빚쟁이 생활과는 안녕이에요.","JPN":"ついに……この泥沼借金生活にも終わりが来るんですね。","ENG":"Finally... Finally, I can say goodbye to my debt-ridden life.","TWN":"終於……終於可以告別討厭的債務生活了。"},"stage":{"bg":"SUMMER_CLIFF","slots":{"L":{"char_id":"RIBBON_DEBT_NECK_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAKER_DEBT_NECK_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};